 58→var rootCmd = &cobra.Command{
 59→	Use:   "nurge [directory]",
 60→	Short: "nurge — outbound that learns",
 61→	Long:  "Nurge is an outbound sales tool that learns from your sent email history.\n\nRun 'nurge <directory>' to create a new project, or 'nurge' in an empty directory to initialize it.",
 62→	RunE:  runInit,
 63→}
 64→
 65→var versionCmd = &cobra.Command{
 66→	Use:         "version",
 67→	Short:       "Print the version of nurge",
 68→	Annotations: map[string]string{"skipAuth": "true"},
 69→	Run: func(cmd *cobra.Command, args []string) {
