 74→// runInit is the shared init logic used by both the root command and the hidden init alias.
 75→func runInit(cmd *cobra.Command, args []string) error {
 76→	dirCreated := ""
 77→
 78→	if len(args) == 1 {
 79→		dir := args[0]
 80→		if err := os.MkdirAll(dir, 0755); err != nil {
 81→			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 82→		}
 83→		abs, err := filepath.Abs(dir)
 84→		if err != nil {
 85→			return err
 86→		}
 87→		if err := os.Chdir(abs); err != nil {
 88→			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 89→		}
 90→		dirCreated = dir
 91→	} else if !initForce {
 92→		// No directory arg: only init if current dir is empty or already initialized
 93→		empty, _ := project.IsDirEmpty(".")
 94→		alreadyInit := project.IsNurgeProject(".")
 95→		if !empty && !alreadyInit {
 96→			return cmd.Help()
 97→		}
 98→	}
 99→
100→	// Check if current directory is non-empty (unless --force)
101→	if !initForce {
102→		empty, err := project.IsDirEmpty(".")
103→		if err != nil {
104→			return err
105→		}
106→		if !empty && !project.IsNurgeProject(".") {
107→			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
108→		}
109→	}
110→
111→	opts := project.Options{
112→		SkipHooks: initSkipHooks,
113→		Force:     initForce,
114→		Verbose:   initVerbose,
115→	}
116→	if err := project.Run(opts); err != nil {
117→		return err
118→	}
119→
120→	if dirCreated != "" {
121→		fmt.Println()
122→		fmt.Printf("  Now run: cd %s\n", dirCreated)
123→		fmt.Println()
124→	}
125→
126→	return nil
127→}
128→
129→// shouldSkipAuth walks the command tree to check if any command in the
130→// chain has the skipAuth annotation. This handles cases like
131→// "nurge account login" where account has skipAuth.
132→func shouldSkipAuth(cmd *cobra.Command) bool {
133→	for c := cmd; c != nil; c = c.Parent() {
134→		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
135→			return true
136→		}
137→	}
138→	return false
139→}
140→
141→func init() {
142→	rootCmd.AddCommand(versionCmd)
143→
144→	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
145→	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
146→	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
147→
148→	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
149→		// Root command (init) skips auth — it's the first thing a user runs
150→		if cmd == rootCmd ||
151→			shouldSkipAuth(cmd) ||
152→			cmd.Name() == "help" ||
153→			cmd.Name() == "completion" {
154→			return nil
155→		}
156→		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
157→		return err
158→	}
159→}
160→
161→// isKnownCommand checks if name matches any registered subcommand.
162→func isKnownCommand(name string) bool {
163→	for _, c := range rootCmd.Commands() {
164→		if c.Name() == name {
165→			return true
166→		}
167→		for _, alias := range c.Aliases {
168→			if alias == name {
169→				return true
170→			}
171→		}
172→	}
173→	return name == "help" || name == "completion"
174→}
175→
176→func Execute() error {
177→	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
178→	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
179→	// when the first arg isn't a known subcommand or flag.
180→	if len(os.Args) > 1 {
181→		first := os.Args[1]
182→		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
183→			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
184→		}
185→	}
186→
187→	// Wrap stdout with a counting writer to measure output size.
188→	cw := metrics.NewCountingWriter(os.Stdout)
189→	rootCmd.SetOut(cw)
190→	origStdout := os.Stdout
191→	r, w, _ := os.Pipe()
192→	os.Stdout = w
193→
194→	// Copy pipe output to counting writer in background.
195→	done := make(chan struct{})
196→	go func() {
197→		buf := make([]byte, 4096)
198→		for {
199→			n, err := r.Read(buf)
200→			if n > 0 {
201→				cw.Write(buf[:n])
202→			}
203→			if err != nil {
204→				break
205→			}
206→		}
207→		close(done)
208→	}()
209→
210→	err := rootCmd.Execute()
211→
212→	// Restore stdout and flush.
213→	w.Close()
214→	<-done
215→	os.Stdout = origStdout
216→
217→	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
218→	cmdName := resolveCommandName()
219→	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
220→		if d, dbErr := db.Open(); dbErr == nil {
221→			_ = metrics.EnsureTable(d)
222→			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
223→			d.Close()
224→		}
225→	}
226→
227→	return err
228→}
229→
230→// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
231→func resolveCommandName() string {
232→	if len(os.Args) < 2 {
233→		return "init"
234→	}
235→	// Build command name from args, skipping flags.
236→	var parts []string
237→	for _, arg := range os.Args[1:] {
238→		if strings.HasPrefix(arg, "-") {
239→			break
240→		}
241→		parts = append(parts, arg)
242→	}
243→	if len(parts) == 0 {
244→		return "init"
245→	}
246→	return strings.Join(parts, " ")
247→}
