118→// SendEmailRequest is the payload for the /api/send-email endpoint.
119→type SendEmailRequest struct {
120→	To       string           `json:"to"`
121→	Cc       string           `json:"cc,omitempty"`
122→	Subject  string           `json:"subject"`
123→	Body     string           `json:"body"`
124→	SendType string           `json:"sendType"`
125→	Sync     bool             `json:"sync"`
126→	TaskID   string           `json:"taskId,omitempty"`
127→	Sequence *SequenceRequest `json:"sequence,omitempty"`
128→}
