130→// SequenceRequest defines sequence enrollment details for a send.
131→type SequenceRequest struct {
132→	SequenceName string         `json:"sequenceName"`
133→	CampaignName string         `json:"campaignName,omitempty"`
134→	ContactName  string         `json:"contactName,omitempty"`
135→	MailboxID    string         `json:"mailboxId,omitempty"`
136→	Steps        []SequenceStep `json:"steps,omitempty"`
137→}
138→
139→// SequenceStep defines a future step in a sequence.
140→type SequenceStep struct {
141→	StepNumber int    `json:"stepNumber"`
142→	StepName   string `json:"stepName,omitempty"`
143→	SendType   string `json:"sendType"`
144→	DelayDays  int    `json:"delayDays"`
145→	Subject    string `json:"subject,omitempty"`
146→	Body       string `json:"body,omitempty"`
147→}
148→
149→// SendEmailResponse is the response from the /api/send-email endpoint.
150→type SendEmailResponse struct {
151→	OK           bool   `json:"ok"`
152→	Queued       bool   `json:"queued,omitempty"`
153→	MessageID    string `json:"messageId,omitempty"`
154→	ProviderID   string `json:"providerId,omitempty"`
155→	EnrollmentID string `json:"enrollmentId,omitempty"`
156→	TaskID       string `json:"taskId,omitempty"`
157→	Error        string `json:"error,omitempty"`
158→}
159→
160→// SendEmail calls the Convex /api/send-email endpoint.
161→func (c *ConvexClient) SendEmail(token string, req SendEmailRequest) (*SendEmailResponse, error) {
162→	body, err := json.Marshal(req)
163→	if err != nil {
164→		return nil, fmt.Errorf("marshaling request: %w", err)
165→	}
166→
167→	httpReq, err := http.NewRequest("POST", c.baseURL+"/api/send-email", bytes.NewReader(body))
168→	if err != nil {
169→		return nil, fmt.Errorf("creating request: %w", err)
