138→// Push sends local state changes to Convex.
139→func (e *Engine) Push() (*PushResult, error) {
140→	state, err := e.loadSyncState()
141→	if err != nil {
142→		return nil, fmt.Errorf("loading sync state: %w", err)
143→	}
144→
145→	result := &PushResult{}
146→	var allRows []account.SyncRow
147→
148→	for _, table := range localTables {
149→		rows, err := e.changedLocalRows(table, state.LastPushAt)
150→		if err != nil {
151→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
152→		}
153→		allRows = append(allRows, rows...)
154→		result.TablesScanned++
155→	}
156→
157→	// Also push email classifications (local authority for the classification field)
158→	classRows, err := e.changedEmailClassifications()
159→	if err != nil {
160→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
161→	}
162→	allRows = append(allRows, classRows...)
163→
164→	if len(allRows) == 0 {
165→		return result, nil
166→	}
167→
168→	// Push in batches
169→	for i := 0; i < len(allRows); i += batchSize {
170→		end := i + batchSize
171→		if end > len(allRows) {
172→			end = len(allRows)
173→		}
174→		batch := allRows[i:end]
175→
176→		resp, err := e.client.PushLocalState(e.token, batch)
177→		if err != nil {
178→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
179→		}
180→
181→		// Update local sync_version from server response
182→		for id, version := range resp.Versions {
183→			for _, row := range batch {
184→				if row.ID == id {
185→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
186→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
187→					}
188→					break
189→				}
190→			}
191→		}
192→		result.RowsPushed += len(batch)
193→	}
194→
195→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
196→	if err := e.saveSyncState(state); err != nil {
197→		return nil, fmt.Errorf("saving sync state: %w", err)
198→	}
199→
200→	return result, nil
201→}
