203→// wouldExceedMailboxLimit returns true if inserting this mailbox ID would exceed the max.
204→// Updates to existing mailboxes are always allowed.
205→func (e *Engine) wouldExceedMailboxLimit(id string) (bool, error) {
206→	var exists bool
207→	err := e.db.QueryRow("SELECT EXISTS(SELECT 1 FROM mailboxes WHERE id = ?)", id).Scan(&exists)
208→	if err != nil {
209→		return false, err
210→	}
211→	if exists {
212→		return false, nil // update, always allowed
213→	}
214→	var count int
215→	err = e.db.QueryRow("SELECT COUNT(*) FROM mailboxes").Scan(&count)
216→	if err != nil {
217→		return false, err
218→	}
219→	return count >= 2, nil
220→}
