222→// upsertRow writes a Convex row into the local SQLite table.
223→func (e *Engine) upsertRow(row account.SyncRow) error {
224→	if len(row.Data) == 0 {
225→		return nil
226→	}
227→
228→	columns := []string{"id"}
229→	placeholders := []string{"?"}
230→	values := []any{row.ID}
231→	updateParts := []string{}
232→
233→	for col, val := range row.Data {
234→		columns = append(columns, col)
235→		placeholders = append(placeholders, "?")
236→		values = append(values, val)
237→		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
238→	}
239→
240→	// Always set sync_version
241→	columns = append(columns, "sync_version")
242→	placeholders = append(placeholders, "?")
243→	values = append(values, row.Version)
244→	updateParts = append(updateParts, "sync_version = excluded.sync_version")
245→
246→	query := fmt.Sprintf(
247→		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
248→		row.Table,
249→		strings.Join(columns, ", "),
250→		strings.Join(placeholders, ", "),
251→		strings.Join(updateParts, ", "),
252→	)
253→
254→	_, err := e.db.Exec(query, values...)
255→	return err
256→}
