209→func (c *ConvexClient) RequestConnectionLink(token, provider string) (string, error) {
210→	body, err := json.Marshal(map[string]string{
211→		"token":    token,
212→		"provider": provider,
213→	})
214→	if err != nil {
215→		return "", fmt.Errorf("marshaling connection link request: %w", err)
216→	}
217→
218→	resp, err := c.httpClient.Post(
219→		c.baseURL+"/api/request-connection-link",
220→		"application/json",
221→		bytes.NewReader(body),
222→	)
223→	if err != nil {
224→		return "", fmt.Errorf("calling request-connection-link: %w", err)
225→	}
226→	defer resp.Body.Close()
227→
228→	data, err := io.ReadAll(resp.Body)
229→	if err != nil {
230→		return "", fmt.Errorf("reading response: %w", err)
231→	}
232→
233→	if resp.StatusCode != 200 {
234→		return "", fmt.Errorf("request-connection-link failed (status %d): %s", resp.StatusCode, string(data))
235→	}
236→
237→	var result struct {
238→		URL   string `json:"url"`
239→		Error string `json:"error,omitempty"`
240→	}
241→	if err := json.Unmarshal(data, &result); err != nil {
242→		return "", fmt.Errorf("parsing response: %w", err)
243→	}
244→	if result.Error != "" {
245→		return "", fmt.Errorf("connection link failed: %s", result.Error)
246→	}
247→	return result.URL, nil
248→}
