  3→import (
  4→	"context"
  5→	_ "embed"
  6→	"encoding/base64"
  7→	"encoding/json"
  8→	"fmt"
  9→	"strings"
 10→
 11→	"golang.org/x/oauth2"
 12→	"golang.org/x/oauth2/google"
 13→)
 14→
 15→//go:embed google_credentials.json
 16→var googleCredentialsJSON []byte
 17→
 18→var googleScopes = []string{
 19→	"openid",
 20→	"https://www.googleapis.com/auth/userinfo.email",
 21→	"https://www.googleapis.com/auth/userinfo.profile",
 22→}
 23→
 24→// googleOAuthConfig builds an oauth2.Config from the embedded credentials.
 25→// The redirect URI is set to http://localhost:<port> at call time.
 26→func googleOAuthConfig(port int) (*oauth2.Config, error) {
 27→	cfg, err := google.ConfigFromJSON(googleCredentialsJSON, googleScopes...)
 28→	if err != nil {
 29→		return nil, fmt.Errorf("parsing google credentials: %w", err)
 30→	}
 31→	cfg.RedirectURL = fmt.Sprintf("http://localhost:%d/callback", port)
 32→	return cfg, nil
 33→}
 34→
 35→// GoogleOAuthResult holds the tokens from a successful Google OAuth flow.
 36→type GoogleOAuthResult struct {
 37→	IDToken      string
 38→	RefreshToken string
 39→}
 40→
 41→// GetGoogleAuthURL returns the Google OAuth consent URL.
 42→func GetGoogleAuthURL(port int, state string) (string, error) {
 43→	cfg, err := googleOAuthConfig(port)
 44→	if err != nil {
 45→		return "", err
 46→	}
 47→
 48→	return cfg.AuthCodeURL(state,
 49→		oauth2.AccessTypeOffline,
 50→		oauth2.SetAuthURLParam("prompt", "select_account"),
 51→	), nil
 52→}
 53→
 54→// ExchangeGoogleCode exchanges an authorization code for tokens.
 55→// Returns the ID token and refresh token.
 56→func ExchangeGoogleCode(ctx context.Context, port int, code string) (*GoogleOAuthResult, error) {
 57→	cfg, err := googleOAuthConfig(port)
 58→	if err != nil {
 59→		return nil, err
 60→	}
 61→
 62→	token, err := cfg.Exchange(ctx, code)
 63→	if err != nil {
 64→		return nil, fmt.Errorf("exchanging code: %w", err)
 65→	}
 66→
 67→	// Extract ID token from the extra fields
 68→	idToken, ok := token.Extra("id_token").(string)
 69→	if !ok || idToken == "" {
 70→		return nil, fmt.Errorf("no id_token in Google response")
 71→	}
 72→
 73→	return &GoogleOAuthResult{
 74→		IDToken:      idToken,
 75→		RefreshToken: token.RefreshToken,
 76→	}, nil
 77→}
 78→
 79→// RefreshIDToken uses a stored refresh token to get a fresh ID token
 80→// without opening the browser.
 81→func RefreshIDToken(ctx context.Context, refreshToken string) (string, error) {
 82→	cfg, err := googleOAuthConfig(0) // port doesn't matter for refresh
 83→	if err != nil {
 84→		return "", err
 85→	}
 86→
 87→	token := &oauth2.Token{RefreshToken: refreshToken}
 88→	src := cfg.TokenSource(ctx, token)
 89→
 90→	newToken, err := src.Token()
 91→	if err != nil {
 92→		return "", fmt.Errorf("refreshing token: %w", err)
 93→	}
 94→
 95→	idToken, ok := newToken.Extra("id_token").(string)
 96→	if !ok || idToken == "" {
 97→		return "", fmt.Errorf("no id_token in refresh response")
 98→	}
 99→
100→	return idToken, nil
101→}
102→
103→// GoogleUserInfo extracts basic user info from the ID token payload.
104→// Local JWT decode (no network call) — only for display purposes.
105→func GoogleUserInfo(idToken string) (email, name string, err error) {
106→	parts := strings.SplitN(idToken, ".", 3)
107→	if len(parts) != 3 {
108→		return "", "", fmt.Errorf("invalid id_token format")
109→	}
110→
111→	payload, err := base64.RawURLEncoding.DecodeString(parts[1])
112→	if err != nil {
113→		return "", "", fmt.Errorf("decoding id_token payload: %w", err)
114→	}
115→
116→	var claims struct {
117→		Email string `json:"email"`
118→		Name  string `json:"name"`
119→	}
120→	if err := json.Unmarshal(payload, &claims); err != nil {
121→		return "", "", fmt.Errorf("parsing id_token claims: %w", err)
122→	}
123→
124→	return claims.Email, claims.Name, nil
125→}
