 10→// Options holds CLI flags for nurge init.
 11→type Options struct {
 12→	SkipHooks bool
 13→	Force     bool
 14→	Verbose   bool
 15→}
 16→
 17→// Step is the interface each init step implements.
 18→type Step interface {
 19→	Name() string
 20→	Done() (bool, error)
 21→	Run() error
 22→}
 23→
 24→// Run executes all init steps in order.
 25→func Run(opts Options) error {
 26→	fmt.Println()
 27→	fmt.Println("  nurge — outbound that learns")
 28→	fmt.Println()
 29→
 30→	steps := buildSteps(opts)
 31→
 32→	for _, s := range steps {
 33→		if !opts.Force {
 34→			done, err := s.Done()
 35→			if err != nil {
 36→				printFail(s.Name(), err)
 37→				return err
 38→			}
 39→			if done {
 40→				printSkip(s.Name())
 41→				continue
 42→			}
 43→		}
 44→
 45→		if err := s.Run(); err != nil {
 46→			printFail(s.Name(), err)
 47→			return err
 48→		}
 49→		printDone(s.Name())
 50→	}
 51→
 52→	return nil
 53→}
 54→
 55→func buildSteps(opts Options) []Step {
 56→	var steps []Step
 57→
 58→	steps = append(steps, &projectStep{})
 59→	steps = append(steps, &databaseStep{})
 60→	steps = append(steps, &gitignoreStep{})
 61→
 62→	if !opts.SkipHooks {
 63→		steps = append(steps, &hooksStep{})
 64→	}
 65→
 66→	steps = append(steps, &skillStep{})
 67→	steps = append(steps, &gitStep{})
 68→	steps = append(steps, &nextStepStep{})
 69→
 70→	return steps
 71→}
