109→// IsNurgeProject returns true if dir contains a .nurge/ directory.
110→func IsNurgeProject(dir string) bool {
111→	info, err := os.Stat(filepath.Join(dir, ".nurge"))
112→	return err == nil && info.IsDir()
113→}
